   104→type StepType = 'upload' | 'mapping' | 'validation' | 'progress';
   105→
   106→export const BulkImportModal: React.FC<BulkImportModalProps> = ({
   107→  isOpen,
   108→  onClose,
   109→  entityType,
   110→  userId,
   111→  onImportComplete,
   112→}) => {
   113→  // FIX: Removed duplicate/conflicting step state variables (`step` vs `currentStep`)
   114→  // and the unused `rawData` state.  There is now a single `step` variable.
   115→  const [step, setStep] = useState<StepType>('upload');
   116→  const { showToast } = useUI();
   117→  const [uploadedData, setUploadedData] = useState<Record<string, any>[] | null>(null);
   118→  const [columnMapping, setColumnMapping] = useState<Record<string, string>>({});
   119→  const [validationErrors, setValidationErrors] = useState<ImportResults['errors']>([]);
   120→  const [importProgress, setImportProgress] = useState({ current: 0, total: 0 });
   121→  const [isImporting, setIsImporting] = useState(false);
   122→
   123→  const config = COLUMN_MAPPINGS[entityType];
   124→
   125→  const downloadTemplate = async () => {
   126→    const ws = utils.json_to_sheet([config.template]);
   127→    const wb = utils.book_new();
   128→    utils.book_append_sheet(wb, ws, 'Template');
   129→    const wbout = XLSX.write(wb, { bookType: 'xlsx', type: 'array' });
   130→    const blob = new Blob([wbout], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
   131→    await exportService.sharePdfBlob(blob, `${entityType}_import_template.xlsx`);
   132→    showToast('Template ready to share', 'success');
   133→  };
   134→
   135→  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
   136→    const file = e.target.files?.[0];
   137→    if (!file) return;
   138→
   139→    const reader = new FileReader();
   140→    reader.onload = (event) => {
   141→      try {
   142→        const data = event.target?.result;
   143→        const workbook = read(data, { type: 'array' });
   144→        const sheetName = workbook.SheetNames[0];
   145→        const worksheet = workbook.Sheets[sheetName];
   146→        const parsed = utils.sheet_to_json(worksheet) as Record<string, any>[];
   147→        setUploadedData(parsed);
   148→
   149→        // Auto-map columns whose headers match our known headerToField entries
   150→        const autoMapping: Record<string, string> = {};
   151→        if (parsed.length > 0) {
   152→          Object.keys(parsed[0]).forEach(header => {
   153→            const field = (config as any).headerToField?.[header];
   154→            if (field) autoMapping[header] = field;
   155→          });
   156→        }
   157→        setColumnMapping(autoMapping);
   158→        setStep('mapping');
   159→      } catch (err) {
   160→        showToast('Failed to parse file', 'error');
   161→      }
   162→    };
   163→    reader.readAsArrayBuffer(file);
   164→  };
   165→
   166→  const validateData = () => {
   167→    if (!uploadedData) return;
   168→    const errors: ImportResults['errors'] = [];
   169→
   170→    uploadedData.forEach((row, idx) => {
   171→      config.required.forEach((field) => {
   172→        const excelCol = Object.keys(columnMapping).find(k => columnMapping[k] === field) || '';
   173→        const value = row[excelCol];
   174→        if (!value || value.toString().trim() === '') {
   175→          errors.push({ row: idx + 2, field, error: `${field} is required` });
   176→        }
   177→      });
   178→
   179→      if (entityType === 'inventory') {
   180→        const saleRateCol = Object.keys(columnMapping).find(k => columnMapping[k] === 'sale_rate') || '';
   181→        const saleRate = row[saleRateCol];
   182→        if (saleRate && isNaN(Number(saleRate))) {
   183→          errors.push({ row: idx + 2, field: 'sale_rate', error: 'Sale rate must be a number' });
   184→        }
   185→        const stockCol = Object.keys(columnMapping).find(k => columnMapping[k] === 'current_stock') || '';
   186→        const stock = row[stockCol];
   187→        if (stock && isNaN(Number(stock))) {
   188→          errors.push({ row: idx + 2, field: 'current_stock', error: 'Stock must be a number' });
   189→        }
   190→      }
   191→
   192→      if (entityType === 'expenses') {
   193→        const dateCol   = Object.keys(columnMapping).find(k => columnMapping[k] === 'date')   || '';
   194→        const amountCol = Object.keys(columnMapping).find(k => columnMapping[k] === 'amount') || '';
   195→        const date   = row[dateCol];
   196→        const amount = row[amountCol];
   197→        if (date && isNaN(Date.parse(date.toString()))) {
   198→          errors.push({ row: idx + 2, field: 'date', error: 'Invalid date format (use YYYY-MM-DD)' });
   199→        }
   200→        if (amount && isNaN(Number(amount))) {
   201→          errors.push({ row: idx + 2, field: 'amount', error: 'Amount must be a number' });
   202→        }
   203→      }
   204→    });
   205→
   206→    setValidationErrors(errors);
   207→    setStep(errors.length === 0 ? 'progress' : 'validation');
   208→  };
   209→
   210→  // FIX: The old implementation wrote one document per Firestore call (sequential),
   211→  // meaning 500 rows triggered 1 000 serial round-trips.  We now use writeBatch()
   212→  // chunked at 450 ops, matching the backup/restore strategy.
   213→  const performImport = async () => {
   214→    if (!uploadedData) return;
   215→
   216→    setIsImporting(true);
   217→    setImportProgress({ current: 0, total: uploadedData.length });
   218→
   219→    const MAX_BATCH = 450;
   220→    let batch = writeBatch(db);
   221→    let opCount = 0;
   222→    let successful = 0;
   223→    let failed = 0;
   224→
   225→    const reverseMapping: Record<string, string> = {};
   226→    Object.entries(columnMapping).forEach(([excelCol, appField]) => {
   227→      reverseMapping[appField] = excelCol;
   228→    });
   229→
   230→    for (let i = 0; i < uploadedData.length; i++) {
   231→      const row = uploadedData[i];
   232→
   233→      const docData: Record<string, any> = { created_at: new Date().toISOString() };
   234→      Object.entries(reverseMapping).forEach(([appField, excelCol]) => {
   235→        let value = row[excelCol];
   236→        if (['sale_rate', 'purchase_rate', 'current_stock', 'min_stock', 'amount', 'gst_percent', 'credit_limit'].includes(appField)) {
   237→          value = Number(value) || 0;
   238→        }
   239→        docData[appField] = value;
   240→      });
   241→
   242→      if (entityType === 'inventory' && !docData.price_type) {
   243→        docData.price_type = 'exclusive';
   244→      }
   245→
   246→      try {
   247→        const ref = doc(collection(db, `users/${userId}/${entityType}`));
   248→        batch.set(ref, docData);
   249→        opCount++;
   250→        successful++;
   251→
   252→        if (opCount >= MAX_BATCH) {
   253→          await batch.commit();
   254→          batch = writeBatch(db);
   255→          opCount = 0;
   256→        }
   257→      } catch (err: any) {
   258→        console.error(`[BulkImport] Row ${i + 2} error:`, err);
   259→        failed++;
   260→      }
   261→
   262→      setImportProgress({ current: i + 1, total: uploadedData.length });
   263→    }
   264→
   265→    // Commit remaining
   266→    if (opCount > 0) {
   267→      try {
   268→        await batch.commit();
   269→      } catch (err) {
   270→        console.error('[BulkImport] Final batch commit error:', err);
   271→      }
   272→    }
   273→
   274→    setIsImporting(false);
   275→    onImportComplete({ successful, failed, errors: [] });
   276→    showToast(
   277→      `Imported ${successful} items${failed > 0 ? `, ${failed} failed` : ''}`,
   278→      successful > 0 ? 'success' : 'error',
   279→    );
   280→    setTimeout(() => onClose(), 2000);
   281→  };
   282→
   283→  if (!isOpen) return null;
   284→
   285→  return (
   286→    <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 backdrop-blur-sm">
   287→      <div className="rounded-2xl shadow-xl max-w-2xl w-full max-h-[90vh] overflow-y-auto border border-white/10" style={{ background: 'var(--app-bg)' }}>
   288→        {/* Header */}
   289→        <div className="sticky top-0 p-6 flex justify-between items-center border-b border-white/08" style={{ background: 'linear-gradient(135deg,#4f46e5,#7c3aed)' }}>
   290→          <div>
   291→            <h2 className="text-2xl font-black text-white">Bulk Import</h2>
   292→            <p className="text-violet-200 text-sm mt-1">{config.displayName}</p>
   293→          </div>
   294→          <button onClick={onClose} className="p-2 hover:bg-white/20 rounded-lg transition text-white">
   295→            <X size={24} />
   296→          </button>
   297→        </div>
   298→
   299→        {/* Content */}
   300→        <div className="p-6" style={{ background: 'var(--app-bg)' }}>
   301→          {step === 'upload' && (
   302→            <div className="space-y-4">
   303→              <div className="p-8 border-2 border-dashed border-[rgba(139,92,246,0.35)] rounded-2xl text-center bg-[rgba(139,92,246,0.08)]">
   304→                <Upload size={48} className="mx-auto text-blue-600 mb-3" />
   305→                <p className="font-bold mb-2">Upload CSV or Excel File</p>
   306→                <p className="text-sm text-[rgba(148,163,184,0.6)] mb-4">Drag and drop or click to select</p>
   307→                <input type="file" accept=".csv,.xlsx,.xls" onChange={handleFileUpload} className="mx-auto block" />
   308→              </div>
   309→              <button
   310→                onClick={downloadTemplate}
   311→                className="w-full flex items-center justify-center gap-2 px-4 py-3 rounded-xl font-bold text-sm transition glass-icon-btn"
   312→              >
   313→                <Download size={18} />
   314→                Download Template
   315→              </button>
   316→            </div>
   317→          )}
   318→
   319→          {step === 'mapping' && uploadedData && (
   320→            <div className="space-y-4">
   321→              <p className="text-sm text-[rgba(148,163,184,0.6)]">Found {uploadedData.length} rows. Map your columns:</p>
   322→              <div className="max-h-64 overflow-y-auto space-y-2">
   323→                {Object.keys(uploadedData[0] || {}).map((header) => (
   324→                  <div key={header} className="flex items-center gap-3">
   325→                    <label className="w-40 text-sm font-bold text-[rgba(203,213,225,0.75)]">{header}</label>
   326→                    <select
   327→                      value={columnMapping[header] || ''}
   328→                      onChange={(e) => setColumnMapping({ ...columnMapping, [header]: e.target.value })}
   329→                      className="flex-1 px-3 py-2 dark-input rounded-lg text-sm"
   330→                    >
   331→                      <option value="">-- Don't Import --</option>
   332→                      {[...config.required, ...config.optional].map((field) => (
   333→                        <option key={field} value={field}>{field}</option>
   334→                      ))}
   335→                    </select>
   336→                  </div>
   337→                ))}
   338→              </div>
   339→              <button
   340→                onClick={validateData}
   341→                className="w-full px-4 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold transition"
   342→              >
   343→                Continue to Validation
   344→              </button>
   345→            </div>
   346→          )}
   347→
   348→          {step === 'validation' && (
   349→            <div className="space-y-4">
   350→              {validationErrors.length > 0 ? (
   351→                <>
   352→                  <div className="p-4 bg-[rgba(239,68,68,0.12)] border border-[rgba(239,68,68,0.2)] rounded-xl">
   353→                    <p className="font-bold text-[#f87171] flex items-center gap-2">
   354→                      <AlertCircle size={20} />
   355→                      {validationErrors.length} Errors Found
   356→                    </p>
   357→                  </div>
   358→                  <div className="max-h-64 overflow-y-auto space-y-2">
   359→                    {validationErrors.map((error, idx) => (
   360→                      <div key={idx} className="p-3 bg-[rgba(239,68,68,0.10)] border border-[rgba(239,68,68,0.18)] rounded-lg text-sm">
   361→                        <p className="font-bold text-[#f87171]">Row {error.row}: {error.field}</p>
   362→                        <p className="text-[#fca5a5]">{error.error}</p>
   363→                      </div>
   364→                    ))}
   365→                  </div>
   366→                  <button onClick={() => setStep('mapping')} className="w-full px-4 py-3 bg-[rgba(255,255,255,0.08)] hover:bg-[rgba(255,255,255,0.12)] rounded-xl font-bold transition">
   367→                    Fix Mapping
   368→                  </button>
   369→                </>
   370→              ) : (
   371→                <>
   372→                  <div className="p-4 bg-[rgba(16,185,129,0.10)] border border-[rgba(16,185,129,0.2)] rounded-xl">
   373→                    <p className="font-bold text-[#34d399] flex items-center gap-2">
   374→                      <CheckCircle size={20} />
   375→                      All {uploadedData?.length} rows validated successfully
   376→                    </p>
   377→                  </div>
   378→                  <button
   379→                    onClick={performImport}
   380→                    disabled={isImporting}
   381→                    className="w-full px-4 py-3 rounded-xl font-bold transition disabled:cursor-not-allowed text-white disabled:opacity-50"
   382→                    style={{ background: 'linear-gradient(135deg,#4f46e5,#7c3aed)' }}
   383→                  >
   384→                    {isImporting ? 'Importing...' : 'Start Import'}
   385→                  </button>
   386→                </>
   387→              )}
   388→            </div>
   389→          )}
   390→
   391→          {step === 'progress' && (
   392→            <div className="space-y-4">
   393→              <div className="flex justify-between mb-2">
   394→                <span className="font-bold">Progress</span>
   395→                <span className="text-sm text-[rgba(148,163,184,0.6)]">
   396→                  {importProgress.current} / {importProgress.total}
   397→                </span>
   398→              </div>
   399→              <div className="w-full bg-[rgba(255,255,255,0.09)] rounded-full h-3 overflow-hidden">
   400→                <div
   401→                  className="h-full bg-gradient-to-r from-blue-500 to-blue-600 transition-all duration-300"
   402→                  style={{ width: `${importProgress.total > 0 ? (importProgress.current / importProgress.total) * 100 : 0}%` }}
   403→                />
   404→              </div>
   405→              {isImporting && (
   406→                <div className="flex items-center justify-center gap-2 text-[rgba(148,163,184,0.6)] mt-4">
   407→                  <Loader2 className="animate-spin" size={20} />
   408→                  <span>Importing...</span>
   409→                </div>
   410→              )}
   411→            </div>
   412→          )}
   413→        </div>
   414→      </div>
   415→    </div>
   416→  );
   417→};
   418→
   419→export default BulkImportModal;
   420→
