   319→function validateRow(row: Record<string, string>, type: ImportType): string[] {
   320→  const errs: string[] = [];
   321→  for (const col of SCHEMA[type]) {
   322→    if (col.required && !row[col.key]?.trim()) errs.push(`"${col.label}" is required`);
   323→  }
   324→  if (type === 'inventory') {
   325→    if (row.sale_rate && isNaN(+row.sale_rate)) errs.push('Sale Rate must be a number');
   326→    if (row.purchase_rate && isNaN(+row.purchase_rate)) errs.push('Purchase Rate must be a number');
   327→    if (row.price_type && !['inclusive','exclusive'].includes(row.price_type.toLowerCase().trim())) errs.push('GST Type must be inclusive or exclusive');
   328→  }
   329→  if (type === 'parties') {
   330→    const r = row.role?.toLowerCase().trim();
   331→    if (r && r !== 'customer' && r !== 'supplier') errs.push('Role must be customer or supplier');
   332→    if (row.gstin && row.gstin.trim() && row.gstin.trim().length !== 15) errs.push('GSTIN must be 15 characters');
   333→  }
   334→  if (type === 'sale' || type === 'purchase') {
   335→    if (row.date && !/^\d{4}-\d{2}-\d{2}$/.test(row.date.trim())) errs.push('Date must be YYYY-MM-DD');
   336→    if (row.total_amount && isNaN(+row.total_amount)) errs.push('Total Amount must be a number');
   337→  }
   338→  if (type === 'transactions') {
   339→    const t = row.type?.toLowerCase().trim();
   340→    if (t && t !== 'received' && t !== 'paid') errs.push('Type must be received or paid');
   341→    if (row.date && !/^\d{4}-\d{2}-\d{2}$/.test(row.date.trim())) errs.push('Date must be YYYY-MM-DD');
   342→    if (row.amount && isNaN(+row.amount)) errs.push('Amount must be a number');
   343→  }
   344→  if (type === 'expenses') {
   345→    if (row.date && !/^\d{4}-\d{2}-\d{2}$/.test(row.date.trim())) errs.push('Date must be YYYY-MM-DD');
   346→    if (row.amount && isNaN(+row.amount)) errs.push('Amount must be a number');
   347→  }
   348→  return errs;
   349→}
