   351→function transformRow(row: Record<string, string>, type: ImportType): any {
   352→  const ts = new Date().toISOString();
   353→  if (type === 'inventory') return {
   354→    name: row.name?.trim(), sale_rate: +row.sale_rate || 0, purchase_rate: +row.purchase_rate || 0,
   355→    current_stock: +row.quantity || 0, unit: row.unit?.trim() || 'Pcs', hsn_code: row.hsn_code?.trim() || '',
   356→    gst_percent: +row.gst_percent || 0, price_type: row.price_type?.toLowerCase().trim() || 'exclusive',
   357→    min_stock: +row.min_stock || 5, primary_supplier: row.primary_supplier?.trim() || '',
   358→    created_at: ts, source: 'bulk_import',
   359→  };
   360→  if (type === 'parties') return {
   361→    name: row.name?.trim(), role: row.role?.toLowerCase().trim() || 'customer',
   362→    contact: row.contact?.trim() || '', gstin: row.gstin?.trim().toUpperCase() || '',
   363→    legal_name: row.legal_name?.trim() || '', address: row.address?.trim() || '',
   364→    site: row.site?.trim() || '', state: row.state?.trim() || '',
   365→    credit_limit: +row.credit_limit || 0, created_at: ts, source: 'bulk_import',
   366→  };
   367→  if (type === 'sale' || type === 'purchase') {
   368→    const items: any[] = [];
   369→    // Dynamically detect how many item slots exist in the mapped row
   370→    let maxSlot = 0;
   371→    for (const key of Object.keys(row)) {
   372→      const m = key.match(/^item(\d+)_name$/);
   373→      if (m) maxSlot = Math.max(maxSlot, parseInt(m[1], 10));
   374→    }
   375→    for (let i = 1; i <= Math.max(maxSlot, ITEM_SLOTS); i++) {
   376→      const name = row[`item${i}_name`]?.trim();
   377→      if (name) {
   378→        const qty  = +row[`item${i}_qty`]  || 0;
   379→        const rate = +row[`item${i}_rate`] || 0;
   380→        items.push({ item_name: name, quantity: qty, rate, total: qty * rate, unit: 'Pcs' });
   381→      }
   382→    }
   383→    const autoTotal = items.reduce((s, it) => s + it.total, 0);
   384→    return {
   385→      date: row.date?.trim(),
   386→      type: type === 'sale' ? 'sell' : 'purchase',
   387→      party_name: row.party_name?.trim(),
