   394→      discount_amount: +row.discount_amount || 0,
   395→      address: row.address?.trim() || '',
   396→      notes: row.notes?.trim() || '',
   397→      items,
   398→      created_at: ts, source: 'bulk_import',
   399→    };
   400→  }
   401→  if (type === 'transactions') return {
   402→    date: row.date?.trim(), type: row.type?.toLowerCase().trim() || 'received',
   403→    party_name: row.party_name?.trim(), amount: +row.amount || 0,
   404→    payment_mode: row.payment_mode?.trim() || '', payment_purpose: row.payment_purpose?.trim() || '',
