   943→/* ─── MICRO ANIMATIONS ───────────────────────────────────── */
   944→@keyframes fadeIn {
   945→  from { opacity: 0; }
   946→  to   { opacity: 1; }
   947→}
   948→@keyframes slideUp {
   949→  from { opacity: 0; transform: translateY(20px) scale(0.97); }
   950→  to   { opacity: 1; transform: translateY(0) scale(1); }
   951→}
   952→@keyframes scaleIn {
   953→  from { opacity: 0; transform: scale(0.92); }
   954→  to   { opacity: 1; transform: scale(1); }
   955→}
   956→@keyframes shimmer {
   957→  0%   { background-position: -200% center; }
   958→  100% { background-position:  200% center; }
   959→}
   960→@keyframes pulse-soft {
   961→  0%, 100% { opacity: 1; }
