   197→// ── Persistence helpers for email-verify banner frequency control ──────────
   198→const VERIFY_PREFIX         = 'evb_';   // email verify banner
   199→const DISMISS_COUNT_KEY     = (uid: string) => `${VERIFY_PREFIX}${uid}_dc`;
   200→const LAST_SHOWN_KEY        = (uid: string) => `${VERIFY_PREFIX}${uid}_ls`;
   201→const MAX_DISMISSALS        = 3;
   202→const SHOW_INTERVAL_MS      = 7 * 24 * 60 * 60 * 1000; // 1 week
   203→
   204→function shouldShowBanner(uid: string): boolean {
   205→  const count = parseInt(localStorage.getItem(DISMISS_COUNT_KEY(uid)) ?? '0', 10);
   206→  if (count >= MAX_DISMISSALS) return false;
   207→  const lastShown = parseInt(localStorage.getItem(LAST_SHOWN_KEY(uid)) ?? '0', 10);
   208→  return Date.now() - lastShown >= SHOW_INTERVAL_MS;
   209→}
   210→
   211→function recordBannerShown(uid: string) {
   212→  localStorage.setItem(LAST_SHOWN_KEY(uid), String(Date.now()));
   213→}
   214→
   215→function recordBannerDismissed(uid: string) {
   216→  const count = parseInt(localStorage.getItem(DISMISS_COUNT_KEY(uid)) ?? '0', 10);
   217→  localStorage.setItem(DISMISS_COUNT_KEY(uid), String(count + 1));
   218→}
