   227→      /*
   228→       * PERF FIX #2: Cap ALL inline backdropFilter values system-wide.
   229→       * The app has 60+ inline style backdropFilter calls — we can't
   230→       * change every JSX file, so we override at the CSS layer.
   231→       * '[style*="backdrop-filter"]' matches any element that has
   232→       * backdrop-filter set via inline style.
   233→       */
   234→      @media (max-width: 900px) {
   235→        /* Class-based backdrop blurs — already defined low above */
   236→        /* Inline style backdrop-filter — nuke heavy values */
   237→        [style*="backdropFilter"],
   238→        [style*="backdrop-filter"] {
   239→          -webkit-backdrop-filter: blur(6px) !important;
   240→          backdrop-filter: blur(6px) !important;
   241→        }
   242→
   243→        /*
   244→         * PERF FIX #3: Kill 'filter: blur()' on decorative blobs.
   245→         * These absolutely-positioned radial-gradient divs with
   246→         * filter:blur(40px) are the single worst offenders — each
   247→         * one triggers a full off-screen rasterization pass.
   248→         * We detect them via [style*="filter"] and zero them out.
   249→         * Real functional filters (e.g. on images) should use a class
   250→         * instead of an inline style — those are unaffected.
   251→         */
   252→        [style*="filter: blur"],
   253→        [style*="filter:blur"] {
   254→          filter: none !important;
   255→        }
   256→
   257→        /*
   258→         * PERF FIX #4: Dot-grid / mesh backgroundImage patterns
   259→         * cause a texture upload every scroll frame on Android Mali.
   260→         * We hide these decorative layers entirely on mobile.
   261→         */
   262→        [style*="backgroundImage"][style*="radial-gradient(circle, white"],
   263→        [style*="backgroundImage"][style*="1px, transparent"] {
   264→          display: none !important;
   265→        }
   266→
   267→        /*
   268→         * PERF FIX #5: Heavy box-shadows cause texture-allocation
   269→         * spikes on low-RAM devices. We reduce, not eliminate, so
   270→         * cards still look distinct.
   271→         */
   272→        [style*="boxShadow"],
   273→        [style*="box-shadow"] {
   274→          box-shadow: 0 1px 6px rgba(0,0,0,0.25) !important;
   275→        }
   276→      }
   277→
   278→      /*
   279→       * PERF FIX #6: Promote scrollable containers to their own
   280→       * compositor layer so finger scroll doesn't block the main thread.
   281→       */
   282→      .overflow-y-auto,
   283→      .overflow-x-auto,
   284→      [class*="overflow-y-"],
   285→      [class*="overflow-x-"] {
   286→        -webkit-overflow-scrolling: touch;
   287→        overscroll-behavior: contain;
   288→        /* Do NOT put will-change here — it creates a new stacking context
   289→           and breaks z-index for modals. Only apply to the hero scroll root. */
   290→      }
   291→
   292→      /*
   293→       * PERF FIX #7: Contain repeated list items so the browser only
   294→       * repaints the affected card, not the whole list.
   295→       */
   296→      .rounded-\\[20px\\],
   297→      .rounded-\\[22px\\],
   298→      .rounded-\\[24px\\],
   299→      .rounded-2xl,
   300→      .rounded-3xl {
   301→        contain: layout style paint;
   302→      }
   303→
   304→      /*
   305→       * PERF FIX #8: Use transform for active scale so it stays on
   306→       * the GPU compositor and never triggers layout.
   307→       * (Already handled by transition-all override above, but being
   308→       *  explicit ensures no regression if Tailwind JIT kicks in.)
   309→       */
   310→      [class*="active:scale-"]:active {
   311→        will-change: transform;
   312→      }
   313→
   314→      /* Reduce all motion for accessibility */
   315→      @media (prefers-reduced-motion: reduce) {
   316→        *, *::before, *::after {
   317→          animation-duration: 0.01ms !important;
   318→          animation-iteration-count: 1 !important;
   319→          transition-duration: 0.01ms !important;
   320→        }
   321→      }
   322→
   323→      /*
   324→       * PERF FIX #9: Touch devices (coarse pointer = phone/tablet)
   325→       * get backdrop-filter completely disabled.
   326→       * The glassmorphism look is preserved via border + semi-transparent
   327→       * background which costs nothing.
   328→       */
   329→      @media (pointer: coarse) {
   330→        [style*="backdropFilter"],
   331→        [style*="backdrop-filter"],
   332→        [class*="backdrop-blur"] {
   333→          -webkit-backdrop-filter: none !important;
   334→          backdrop-filter: none !important;
   335→        }
   336→      }
   337→    `;
   338→    document.head.appendChild(style);
   339→    return () => {
   340→      const el = document.getElementById('seo-global-styles');
   341→      if (el) document.head.removeChild(el);
   342→    };
   343→  }, []);
   344→  return null;
   345→};
