    41→export function normalizeThemeId(input: unknown): ThemePresetId {
    42→  if (typeof input !== 'string') return DEFAULT_THEME_ID;
    43→  const id = input.trim().toLowerCase();
    44→  const known = new Set<string>([...THEME_PRESETS.map((p) => p.id), 'custom']);
    45→  return (known.has(id) ? (id as ThemePresetId) : DEFAULT_THEME_ID);
