     1→/**
     2→ * useScrollMemory(key)
     3→ *
     4→ * Attach to any scrollable element to automatically save and restore
     5→ * its scroll position when the screen is left and returned to.
     6→ *
     7→ * Usage:
     8→ *   const scrollRef = useScrollMemory('inventory');
     9→ *   return <div ref={scrollRef} className="flex-1 overflow-y-auto">...</div>;
    10→ *
    11→ * The hook:
    12→ * • Throttles saves to once per 400 ms (no keystroke-per-frame writes)
    13→ * • Restores scroll after an 80 ms delay so content has time to render
    14→ * • Saves final position on unmount
    15→ * • Handles key changes cleanly (saves old, restores new)
    16→ *
    17→ * Module 9
    18→ */
    19→
    20→import { useRef, useEffect, MutableRefObject } from 'react';
    21→import { saveScrollPosition, getScrollPosition } from '../utils/scrollMemory';
    22→
    23→const THROTTLE_MS = 400;
    24→const RESTORE_DELAY_MS = 80;
    25→
    26→export function useScrollMemory(key: string): MutableRefObject<HTMLDivElement | null> {
    27→  const ref           = useRef<HTMLDivElement | null>(null);
    28→  const throttleTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
    29→  const restoreTimer  = useRef<ReturnType<typeof setTimeout> | null>(null);
    30→  const prevKey       = useRef(key);
    31→
    32→  // Restore on mount (and on key change)
    33→  useEffect(() => {
    34→    // If key changed, save old position first
    35→    if (prevKey.current !== key) {
    36→      if (ref.current) saveScrollPosition(prevKey.current, ref.current.scrollTop);
    37→      prevKey.current = key;
    38→    }
    39→
    40→    const saved = getScrollPosition(key);
    41→    if (saved > 0) {
    42→      restoreTimer.current = setTimeout(() => {
    43→        if (ref.current) ref.current.scrollTop = saved;
    44→      }, RESTORE_DELAY_MS);
    45→    }
    46→
    47→    return () => {
    48→      if (restoreTimer.current) clearTimeout(restoreTimer.current);
    49→    };
    50→  }, [key]);
    51→
    52→  // Throttled scroll save + final-position save on unmount
    53→  useEffect(() => {
    54→    const el = ref.current;
    55→    if (!el) return;
    56→
    57→    const onScroll = () => {
    58→      if (throttleTimer.current) return;
    59→      throttleTimer.current = setTimeout(() => {
    60→        if (ref.current) saveScrollPosition(key, ref.current.scrollTop);
    61→        throttleTimer.current = null;
    62→      }, THROTTLE_MS);
    63→    };
    64→
    65→    el.addEventListener('scroll', onScroll, { passive: true });
    66→
    67→    return () => {
    68→      el.removeEventListener('scroll', onScroll);
    69→      // Cancel pending throttle
    70→      if (throttleTimer.current) {
    71→        clearTimeout(throttleTimer.current);
    72→        throttleTimer.current = null;
    73→      }
    74→      // Persist final position on unmount
    75→      if (ref.current) saveScrollPosition(key, ref.current.scrollTop);
    76→    };
    77→  // Key is stable for the lifetime of this effect — ref.current changes are fine
    78→  // eslint-disable-next-line react-hooks/exhaustive-deps
    79→  }, [key]);
    80→
    81→  return ref;
    82→}
