     1→/**
     2→ * scrollMemory — Lightweight per-tab/view scroll position persistence
     3→ *
     4→ * Uses sessionStorage (not localStorage) because scroll offsets are
     5→ * session-scoped — they don't need to survive process kill.
     6→ *
     7→ * Bounded at MAX_ENTRIES with FIFO eviction to stay memory-safe.
     8→ *
     9→ * Module 9, 11
    10→ */
    11→
    12→const SS_KEY     = 'scroll_mem_v1';
    13→const MAX_ENTRIES = 25;
    14→
    15→type ScrollMap = Record<string, number>;
    16→
    17→// ── Internal helpers ──────────────────────────────────────────────────────────
    18→
    19→function read(): ScrollMap {
    20→  try {
    21→    const raw = sessionStorage.getItem(SS_KEY);
    22→    if (!raw) return {};
    23→    const p = JSON.parse(raw);
    24→    return (p && typeof p === 'object') ? p as ScrollMap : {};
    25→  } catch { return {}; }
    26→}
    27→
    28→function write(map: ScrollMap): void {
    29→  try { sessionStorage.setItem(SS_KEY, JSON.stringify(map)); } catch {}
    30→}
    31→
    32→// ── Public API ────────────────────────────────────────────────────────────────
    33→
    34→/**
    35→ * Save a scroll offset for a given key.
    36→ * Keys are typically the active tab name ("inventory", "ledger", etc.).
    37→ */
    38→export function saveScrollPosition(key: string, top: number): void {
    39→  const map  = read();
    40→  const keys = Object.keys(map);
    41→  // Evict oldest entry when at capacity and key is new
    42→  if (keys.length >= MAX_ENTRIES && !(key in map)) {
    43→    delete map[keys[0]];
    44→  }
    45→  map[key] = top;
    46→  write(map);
    47→}
    48→
    49→/** Retrieve saved offset, or 0 if not found. */
    50→export function getScrollPosition(key: string): number {
    51→  return read()[key] ?? 0;
    52→}
    53→
    54→/** Remove a saved offset (e.g. when a list resets intentionally). */
    55→export function clearScrollPosition(key: string): void {
    56→  const map = read();
    57→  delete map[key];
    58→  write(map);
